from typing import List
from collections import defaultdict


class Solution:
    def kthDistinct(self, arr: List[str], k: int) -> str:
        dist=defaultdict(int)
        distinct_nums=[]
        for i in arr:
            dist[i]+=1
            # distinct_nums.add(i)
            # if dist[i]>1:
            #     distinct_nums.remove(i)
        for j in dist:
            if dist[j]==1:
                distinct_nums.append(j)
        if len(distinct_nums)==0 and len(distinct_nums)<k:
            return ''
        print(len(distinct_nums))
        # print((distinct_nums[k-1]))
        return distinct_nums[k-1]


